solution_code:
#include <array>
#include <functional>
#include <iostream>

int main() {
    int s0 {}, s1 {}, s2 {}, s3 {};
    std::cin >> s0 >> s1 >> s2 >> s3;
    int bonus {};
    std::cin >> bonus;

    std::array<std::reference_wrapper<int>, 4> refs {
        std::ref(s0), std::ref(s1), std::ref(s2), std::ref(s3)
    };

    for (int& v : refs) {
        v += bonus;
    }

    std::cout << s0 << ' ' << s1 << ' ' << s2 << ' ' << s3 << '\n';
    return 0;
}

